mapper.update:
UPDATE message_statistics_timeseries
   SET received = received + #{received},
       filtered = filtered + #{filtered},
       queued   = queued   + #{queued},
       sent     = sent     + #{sent},
       error    = error    + #{error}
 WHERE server_id           = #{serverId}
   AND channel_id          = #{channelId}
   AND connector_id        = #{connectorId}
   AND ts                  = #{ts}
   AND bucket_size_minutes = #{bucketSizeMinutes}

mapper.select:
	SELECT id, channel_id, connector_id, ts, bucket_size_minutes, received, filtered, queued, sent, error, server_id
  	FROM message_statistics_timeseries
 	WHERE server_id = #{serverId} 
 		AND channel_id = #{channelId} 
 		AND connector_id = ''
   		AND bucket_size_minutes = #{intervalMinutes}
   		 AND ts  >=  #{startTs} 
   		   AND ts  <   #{endTs}   
 	ORDER BY ts ASC

	SSELECT id, channel_id, connector_id, ts, bucket_size_minutes, received, filtered, queued, sent, error, server_id
